  def _clean_obj(o: str) -> str:
          # Remove surrounding quotes
          o = o.strip('"')
          # Strip trailing .0 for whole numbers
          if o.replace('.', '', 1).isdigit():
              # Convert to float then int if no fractional part
              try:
                  f = float(o)
                  if f.is_integer():
                      o = str(int(f))
                  else:
                      o = str(f)
              except ValueError:
                  pass
          return o
